const getWikiContent = (nodeName) => {
  try {
    const node = $(nodeName).first();
    return node ? node.json.content : "";
  } catch (error) {
    return "";
  }
};

// --- EXTRAER DATOS LIMPIOS ---
const productPlanningBD = getWikiContent('1. Cargar Product Planning Before Discovery');
const releasePlanningEjemplo = getWikiContent('1. Cargar ejemplo de Release Planning');


// --- RETORNAR OBJETO UNIFICADO ---
return [{
  json: {
    // Metadatos para tu control
    fecha_proceso: new Date().toISOString(),

    contexto_product_planning_bd: productPlanningBD,
    contexto_release_planning_ejemplo: releasePlanningEjemplo,
  }
}];

